-- Update FAQ: remove LATAM question, fix em dashes
UPDATE page_sections SET 
  title = 'Lo que más nos preguntan sobre ser partner HubSpot en Chile',
  metadata = jsonb_set(metadata::jsonb, '{faqs}', '[{"q":"¿Qué es un HubSpot Partner?","a":"Un HubSpot Partner es una empresa certificada por HubSpot para implementar, configurar y operar sus productos. Los partners están organizados en niveles según su experiencia y volumen de clientes: Starter, Gold, Platinum, Diamond y Elite. RevOps LATAM es HubSpot Platinum Partner en Chile, uno de los niveles más altos del ecosistema de partners en la región."},{"q":"¿Cuál es la diferencia entre un partner Platinum y uno Gold?","a":"El nivel Platinum refleja mayor experiencia acumulada, mayor volumen de implementaciones exitosas y certificaciones más avanzadas del equipo. En el directorio global de HubSpot hay miles de partners, los niveles más altos representan una fracción pequeña. En Chile, los partners Platinum son especialmente escasos."},{"q":"¿Cómo elegir un partner de HubSpot en Chile?","a":"Más allá del nivel de partnership, hay tres preguntas que importan: ¿El partner entiende tu tipo de negocio y proceso comercial? ¿Tiene experiencia operando HubSpot después de la implementación, o solo configura y se va? ¿Puede mostrarte implementaciones reales en empresas similares a la tuya? El nivel Platinum es una señal de experiencia, pero no reemplaza el fit estratégico."},{"q":"¿Cuánto cuesta implementar HubSpot con un partner en Chile?","a":"El costo depende de la complejidad del proyecto: los módulos a implementar, el tamaño del equipo, las integraciones requeridas y el nivel de personalización. En RevOps LATAM trabajamos con una calculadora de precios que entrega un rango según las características de cada proyecto. El punto de partida siempre es el diagnóstico, para no cotizar una implementación sin entender qué necesita realmente la empresa."},{"q":"¿Puedo contratar HubSpot directamente sin un partner?","a":"Sí. HubSpot se puede contratar directamente en hubspot.com. Un partner agrega valor en la implementación, la configuración estratégica, la integración con otras herramientas y la operación continua. Si solo necesitas la licencia, no necesitas un partner. Si quieres que HubSpot funcione de verdad en tu operación, un partner con experiencia hace la diferencia entre una inversión que rinde y una que se desperdicia."},{"q":"¿RevOps LATAM solo trabaja con HubSpot?","a":"Sí. HubSpot es el ecosistema central de todo lo que hacemos. No somos technology-agnostic, somos especialistas. Esa especialización profunda es lo que nos permite implementar y operar HubSpot con el nivel de detalle que los resultados requieren. Podemos integrarlo con prácticamente cualquier herramienta del stack del cliente, pero el motor siempre es HubSpot."},{"q":"¿Qué diferencia a RevOps LATAM de otras consultoras HubSpot?","a":"Tres cosas concretas: primero, siempre empezamos con diagnóstico, nunca proponemos soluciones antes de entender el problema. Segundo, no entregamos y desaparecemos, ofrecemos operación continua post-implementación. Tercero, no somos una agencia que configura HubSpot: somos una consultora de Revenue Operations que usa HubSpot como motor central para construir operaciones comerciales que escalan."}]'::jsonb)
WHERE id = '812a865a-10ea-44b8-a259-51480650fc4e';

